module top_module(SEL, obf_D_OUT);input  [1:0] SEL; 
    output reg [3:0] obf_D_OUT;  



    always @ (SEL)
    begin
       case (SEL)
          0: obf_D_OUT = 4'b1110;  
          1: obf_D_OUT = 4'b1101; 
          2: obf_D_OUT = 4'b1011;
          3: obf_D_OUT = 4'b0111;
          default obf_D_OUT = 0; 
       endcase 
    end 

	endmodule
